    public void disableBiometricAuth() {
        prefs.edit()
                .remove(PREF_ENCRYPTED_TOKEN)
                .remove(PREF_IV)
                .putBoolean(PREF_BIOMETRIC_ENABLED, false)
                .apply();
        
        try {
            KeyStore keyStore = KeyStore.getInstance(KEYSTORE_PROVIDER);
            keyStore.load(null);
            keyStore.deleteEntry(KEY_ALIAS);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private void generateSecretKey() {
        try {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, KEYSTORE_PROVIDER);

            KeyGenParameterSpec keyGenParameterSpec = new KeyGenParameterSpec.Builder(
                    KEY_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setUserAuthenticationRequired(true)
                    .setInvalidatedByBiometricEnrollment(true)
                    .build();

            keyGenerator.init(keyGenParameterSpec);
            keyGenerator.generateKey();
        } catch (Exception e) {
            throw new RuntimeException("Failed to generate secret key", e);
        }
    }

    private SecretKey getSecretKey() {
        try {
            KeyStore keyStore = KeyStore.getInstance(KEYSTORE_PROVIDER);
            keyStore.load(null);
            return (SecretKey) keyStore.getKey(KEY_ALIAS, null);
        } catch (Exception e) {
            throw new RuntimeException("Failed to get secret key", e);
        }
    }

    private Cipher getCipher() {
        try {
            return Cipher.getInstance(KeyProperties.KEY_ALGORITHM_AES + "/"
                    + KeyProperties.BLOCK_MODE_GCM + "/"
                    + KeyProperties.ENCRYPTION_PADDING_NONE);
        } catch (Exception e) {
            throw new RuntimeException("Failed to get cipher", e);
        }
    }

    private boolean encryptAndStoreToken(String token, Cipher cipher) {
        try {
            byte[] encryptedToken = cipher.doFinal(token.getBytes(StandardCharsets.UTF_8));
            byte[] iv = cipher.getIV();

            String encryptedTokenString = Base64.encodeToString(encryptedToken, Base64.DEFAULT);
            String ivString = Base64.encodeToString(iv, Base64.DEFAULT);

            prefs.edit()
                    .putString(PREF_ENCRYPTED_TOKEN, encryptedTokenString)
                    .putString(PREF_IV, ivString)
                    .apply();

            return true;
        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    private String decryptToken(Cipher cipher) {
        try {
            String encryptedTokenString = prefs.getString(PREF_ENCRYPTED_TOKEN, null);
            if (encryptedTokenString == null) {
                return null;
            }

            byte[] encryptedToken = Base64.decode(encryptedTokenString, Base64.DEFAULT);
            byte[] decryptedToken = cipher.doFinal(encryptedToken);
            return new String(decryptedToken, StandardCharsets.UTF_8);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

