package com.example.app;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {
    private EditText usernameInput;
    private EditText passwordInput;
    private CheckBox biometricCheckbox;
    private Button loginButton;
    private BiometricAuthManager biometricAuthManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        biometricAuthManager = new BiometricAuthManager(this);

        usernameInput = findViewById(R.id.username_input);
        passwordInput = findViewById(R.id.password_input);
        biometricCheckbox = findViewById(R.id.biometric_checkbox);
        loginButton = findViewById(R.id.login_button);

        if (!biometricAuthManager.isBiometricAvailable()) {
            biometricCheckbox.setEnabled(false);
            biometricCheckbox.setText("Biometric not available");
        }

        if (biometricAuthManager.isBiometricEnabled()) {
            attemptBiometricLogin();
        }

        loginButton.setOnClickListener(v -> performLogin());
    }

    private void attemptBiometricLogin() {
        biometricAuthManager.authenticateWithBiometric(this, 
                new BiometricAuthManager.BiometricAuthCallback() {
            @Override
            public void onSuccess(String sessionToken) {
                proceedToMainActivity(sessionToken);
            }

            @Override
            public void onError(String error) {
                // User can still use password login
            }
        });
    }

    private void performLogin() {
        String username = usernameInput.getText().toString();
        String password = passwordInput.getText().toString();

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter username and password", 
                    Toast.LENGTH_SHORT).show();
            return;
        }

        // Simulate server authentication
        authenticateWithServer(username, password, new AuthCallback() {
            @Override
            public void onSuccess(String sessionToken) {
                if (biometricCheckbox.isChecked() && 
                        biometricAuthManager.isBiometricAvailable()) {
                    enableBiometricAuth(sessionToken);
                } else {
                    proceedToMainActivity(sessionToken);
                }
            }

            @Override
            public void onError(String error) {
                Toast.makeText(LoginActivity.this, "Login failed: " + error, 
                        Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void enableBiometricAuth(String sessionToken) {
        biometricAuthManager.enableBiometricAuth(this, sessionToken, 
                new BiometricAuthManager.BiometricAuthCallback() {
            @Override
            public void onSuccess(String token) {
                Toast.makeText(LoginActivity.this, 
                        "Biometric authentication enabled", Toast.LENGTH_SHORT).show();
                proceedToMainActivity(token);
            }

            @Override
            public void onError(String error) {
                Toast.makeText(LoginActivity.this, 
                        "Failed to enable biometric: " + error, Toast.LENGTH_SHORT).show();
                proceedToMainActivity(sessionToken);
            }
        });
    }

    private void authenticateWithServer(String username, String password, 
                                       AuthCallback callback) {
        // Simulate network call
        new Thread(() -> {
            try {
                Thread.sleep(1000);
                // In real app, call your authentication API
                String sessionToken = "session_token_" + System.currentTimeMillis();
                runOnUiThread(() -> callback.onSuccess(sessionToken));
            } catch (InterruptedException e) {
                runOnUiThread(() -> callback.onError(e.getMessage()));
            }
        }).start();
    }

    private void proceedToMainActivity(String sessionToken) {
        SessionManager.getInstance(this).setSessionToken(sessionToken);
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }

    interface AuthCallback {
        void onSuccess(String sessionToken);
        void onError(String error);
    }
}

// SessionManager.java
package com.example.app;

import android.content.Context;

public class SessionManager {
    private static SessionManager instance;
    private String sessionToken;

    private SessionManager(Context context) {
    }

    public static synchronized SessionManager getInstance(Context context) {
        if (instance == null) {
            instance = new SessionManager(context.getApplicationContext());
        }
        return instance;
    }

    public void setSessionToken(String token) {
        this.sessionToken = token;
    }

    public String getSessionToken() {
        return sessionToken;
    }

    public boolean isAuthenticated() {
        return sessionToken != null && !sessionToken.isEmpty();
    }

    public void clearSession() {
        sessionToken = null;
    }
}

