package com.example.app;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {
    private BiometricAuthManager biometricAuthManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        biometricAuthManager = new BiometricAuthManager(this);
        SessionManager sessionManager = SessionManager.getInstance(this);

        if (!sessionManager.isAuthenticated()) {
            redirectToLogin();
            return;
        }

        TextView welcomeText = findViewById(R.id.welcome_text);
        Button logoutButton = findViewById(R.id.logout_button);
        Button disableBiometricButton = findViewById(R.id.disable_biometric_button);

        welcomeText.setText("Welcome! You are authenticated.");

        logoutButton.setOnClickListener(v -> {
            sessionManager.clearSession();
            redirectToLogin();
        });

        if (biometricAuthManager.isBiometricEnabled()) {
            disableBiometricButton.setVisibility(Button.VISIBLE);
            disableBiometricButton.setOnClickListener(v -> {
                biometricAuthManager.disableBiometricAuth();
                disableBiometricButton.setVisibility(Button.GONE);
            });
        } else {
            disableBiometricButton.setVisibility(Button.GONE);
        }
    }

    private void redirectToLogin() {
        Intent intent = new Intent(this, LoginActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}